CREATE TABLE `landing_users` (
  `id` char(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `hero_title` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
