('3d961fd8-34b7-4e22-b166-e046d3d6f991', 'driver', 'Driver Subscription', 'Choose how Driver will get notified about Sent notification on Driver Subscription Successfully', 1, 0, 0, 'Subscribed Succesfully', 'logo-light.png', '\n                                    <p>Hello {name}</p>\n                                    <p>We are writing to confirm that you have successfully transferred an amount from your wallet.</p>\n                                    <p><strong>Transaction Details</strong></p>\n                                    <p><strong>Transaction Id:</strong> {transaction_id}</p>\n                                    <p><strong>Amount:</strong> {currency}{amount}</p>\n                                    <p><strong>Current Balance:</strong>{currency}{current_balance}</p>\n                                    <p>If you did not initiate this transfer, please contact our support team immediately.</p>\n                                    <p>Thank you for using our services!</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', 'https://play.google.com/store/apps/details?id=tagxi.bidding.user', 0, 'profile-bg.jpg', 0, '{\"footer_fblink\":\"https:\\/\\/www.facebook.com\\/\",\"footer_instalink\":\"https:\\/\\/www.instagram.com\\/\",\"footer_twitterlink\":\"https:\\/\\/x.com\\/\",\"footer_linkedinlink\":\"https:\\/\\/in.linkedin.com\\/\"}', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 1, 1, 1, 1, 'Subscribed Succesfully', 'You have subscribed successfully', '{\"email_subject\":\"Subscribed Succesfully\",\"mail_body\":\"\\n                                    <p>Hello {name}<\\/p>\\n                                    <p>We are writing to confirm that you have successfully transferred an amount from your wallet.<\\/p>\\n                                    <p><strong>Transacti