('64bdd2b5-8b63-4bc3-bdb7-9a252ef54334', 'user', 'User Account Disapproval', 'Choose how User will get notified about Sent notification on account disapproval', 1, 1, 1, 'Account Disapproval', 'logo-light.png', '\n                                    <p>Hello {name}</p>\n                                    <p> We regret to inform you that your application to become a user with our taxi service has not been approved at this time.</p>   \n                                    <p>If you have any questions or need further clarification, feel free to contact our support team.</p>        \n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'Button', 'https://play.google.com/store/apps/details?id=tagxi.bidding.user', 0, 'profile-bg.jpg', 0, '{\"footer_fblink\":\"https:\\/\\/www.facebook.com\\/\",\"footer_instalink\":\"https:\\/\\/www.instagram.com\\/\",\"footer_twitterlink\":\"https:\\/\\/x.com\\/\",\"footer_linkedinlink\":\"https:\\/\\/in.linkedin.com\\/\"}', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 1, 1, 1, 1, 'Account Declined 🙁️', 'Your Account declined due to some reason. please contact our admin', '{\"email_subject\":\"Account Disapproval\",\"mail_body\":\"\\n                                    <p>Hello {name}<\\/p>\\n                                    <p> We regret to inform you that your application to become a user with our taxi service has not been approved at this time.<\\/p>   \\n                                    <p>If you have any questions or need further clarification, feel free to contact our support team.<\\/p>        \\n                                    <p>Best regards, <\\/p>         \\n                                    <p>Sangvish<\\/p>\",\"button_name\":\"Button\",\"footer_content\":\"<p>If you have any queries , Please email us support@gmail.com.They will answer the q