INSERT INTO `notification_channels_translations` (`id`, `notification_channel_id`, `email_subject`, `mail_body`, `button_name`, `footer_content`, `footer_copyrights`, `push_title`, `push_body`, `locale`, `created_at`, `updated_at`) VALUES
(1, '4f0f5c1f-ba39-4296-bebb-07d48ccb8649', 'Registration Mail', '<p>Hello {name}</p>\n                                    <p>Thank you for signing up with us, your trusted taxi app. Your registration was successful, and we are excited to have you on board.</p>\n                                    <p>Your Account Details</p>\n                                    <p>Email: {email}</p>\n                                    <p>Mobile Number: {mobile}</p>\n                                    <p>We are now ready to help you with your transportation needs! To get started, simply click the button below to log in to your account:</p> \n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'Log in', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Register successfully', 'Register successfully', 'en', NULL, NULL),
(2, '4f0f5c1f-ba39-4296-bebb-07d48ccb8649', 'Courrier d\'inscription', '<p>Bonjour {name}</p>\n                                                <p>Merci de vous être inscrit auprès de nous, votre application de taxi de confiance. Votre inscription a réussi et nous sommes ravis de vous compter parmi nous.</p>\n                                                <p>Détails de votre compte</p>\n                                                <p>E-mail : {email}</p>\n                                                <p>Numéro de mobile : {mobile}</p>\n                                                <p>Nous sommes maintenant prêts à vous aider avec vos besoins de transport ! Pour commencer, cliquez simplement sur le bouton ci-dessous pour vous connecter à votre compte :</p> \n                                                <p>Meilleures salutations, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Titre de notification en français', 'Corps de notification en français', 'fr', NULL, NULL),
(3, '4f0f5c1f-ba39-4296-bebb-07d48ccb8649', 'Correo de registro', '<p>Hola {name}</p>\n                                                <p>Gracias por registrarte con nosotros, tu aplicación de taxis de confianza. Su registro fue exitoso y estamos emocionados de tenerlo a bordo.</p>\n                                                <p>Detalles de su cuenta</p>\n                                                <p>Correo electrónico: {email}</p>\n                                                <p>Número de móvil: {mobile}</p>\n                                                <p>¡Ahora estamos listos para ayudarle con sus necesidades de transporte! Para comenzar, simplemente haga clic en el botón a continuación para iniciar sesión en su cuenta:</p> \n                                                <p>Saludos cordiales,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Título de la notificación en español', 'Cuerpo de la notificación en español', 'es', NULL, NULL),
(4, '4f0f5c1f-ba39-4296-bebb-07d48ccb8649', 'بريد التسجيل', '<p>{مرحبًا {الاسم</p>\n                                                <p>نشكرك على الاشتراك معنا، تطبيق سيارات الأجرة الموثوق به. تم تسجيلك بنجاح، ونحن متحمسون لانضمامك إلينا.</p>\n                                                <p>تفاصيل حسابك</p>\n                                                <p>البريد الإلكتروني: {email}</p>\n                                                <p>رقم الجوال: {mobile}</p>\n                                                <p>نحن الآن على استعداد لمساعدتك في تلبية احتياجات النقل الخاصة بك! للبدء، ما عليك سوى النقر على الزر أدناه لتسجيل الدخول إلى حسابك:</p> \n                                                <p>مع أطيب التحيات</p>         \n                                                ', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'Benachrichtigungstitel auf Deutsch', 'Benachrichtigungstext auf Deutsch', 'ar', NULL, NULL),
(5, '880381c6-544a-44dd-92de-3c1e6eba79ef', 'Driver Assigned For Ride', '\n                                    <p>Hello {name}</p>\n                                    <p>Your Ride Later Trip is Confirmed</p>\n                                    <p>Thank You for Riding with us</p>\n                                    <p>Your \"ride later\" trip has been successfully scheduled.</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'New Trip Requested 😊️', 'New Trip Requested, you can accept or Reject the request', 'en', NULL, NULL),
(6, '880381c6-544a-44dd-92de-3c1e6eba79ef', 'Chauffeur affecté au trajet', '<p>Bonjour {name}</p>\n                                                <p>Votre voyage Ride Later est confirmé</p>\n                                                <p>Merci d\'avoir roulé avec nous</p>\n                                                <p>Votre voyage « rouler plus tard » a été planifié avec succès.</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Nouveau voyage demandé 😊️', 'Nouveau voyage demandé, vous pouvez accepter ou refuser la demande', 'fr', NULL, NULL),
(7, '880381c6-544a-44dd-92de-3c1e6eba79ef', 'Conductor asignado para el viaje', '<p>Hola {name}</p>\n                                                <p>Su viaje de viaje más tarde está confirmado</p>\n                                                <p>Gracias por viajar con nosotros</p>\n                                                <p>Su viaje \"viajar más tarde\" se ha programado correctamente.</p>\n                                                <p>Atentamente, </p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Nuevo viaje solicitado 😊️', 'Nuevo Viaje Solicitado, puedes aceptar o Rechazar la solicitud', 'es', NULL, NULL),
(8, '880381c6-544a-44dd-92de-3c1e6eba79ef', 'السائق المخصص للركوب', '<p>مرحبًا {name}</p>\n                                                <p>تم تأكيد رحلتك اللاحقة</p>\n                                                <p>شكرا لركوبك معنا</p>\n                                                <p>تمت جدولة رحلتك \"الركوب لاحقًا\" بنجاح.</p>\n                                                <p>أطيب التحيات, </p>         \n                                                <p>برامج إم آي</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'مطلوب رحلة جديدة 😊️', 'تم طلب رحلة جديدة، يمكنك قبول الطلب أو رفضه', 'ar', NULL, NULL),
(9, '61c029dc-ce60-436f-9204-e51e1ed0de01', 'Invoice For Ride', '\n                                    <p>Hello {name}</p>\n                                    <p>Thank You for Riding with us</p>\n                                    <p><strong>Here is the summary of your recent trip: <strong></p>', 'Reset Password', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Driver Ended the trip', 'Driver finished the ride, Please help us by rating the driver', 'en', NULL, NULL),
(10, '61c029dc-ce60-436f-9204-e51e1ed0de01', 'Facture pour le trajet', '<p>Bonjour {name}</p>\n                                                <p>Merci d\'avoir roulé avec nous</p>\n                                                <p>Voici le résumé de votre récent voyage :</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Chauffeur A terminé le voyage', 'Le chauffeur a terminé le trajet. Aidez-nous en évaluant le chauffeur.', 'fr', NULL, NULL),
(11, '61c029dc-ce60-436f-9204-e51e1ed0de01', 'Factura por viaje', '<p>Hola {name}</p>\n                                                <p>Gracias por viajar con nosotros</p>\n                                                <p>Aquí está el resumen de su reciente viaje</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'El conductor finalizó el viaje.', 'El conductor terminó el viaje. Ayúdenos calificando al conductor.', 'es', NULL, NULL),
(12, '61c029dc-ce60-436f-9204-e51e1ed0de01', 'فاتورة للركوب', '<p>مرحبًا {name}</p>\n                                                <p>شكرا لركوبك معنا</p>\n                                                <p>فيما يلي ملخص رحلتك الأخيرة:</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'أنهى السائق الرحلة', 'أنهى السائق الرحلة، الرجاء مساعدتنا بتقييم السائق', 'ar', NULL, NULL),
(13, 'cc12aa58-260a-4773-9286-439dafa92ad7', 'Referral Code User', '\n                                    <p>Hello {name}</p>\n                                    <p>Thanks you! We are excited to offer you a referral code that you can share with your friends,\n                                    family, or colleagues.</p>\n                                    <p>When they use this referral code, they will receive a discount on their first ride, and you will earn rewards as well.</p>\n                                    <p>Share this code with others, and start earning rewards today! The more you refer, the more you can earn!</p>\n                                    <p>To use the referral code, simply share it with the person you refer,\n                                     and they can enter it during the booking process on our app.</p>\n                                     <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'Share', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'You have Earned with your Referral code 😊️', 'We are happy to inform you that you have earned money with your referral code', 'en', NULL, NULL),
(14, 'cc12aa58-260a-4773-9286-439dafa92ad7', 'Utilisateur du code de référence', '<p>Bonjour {name}</p>\n                                                <p>Merci! Nous sommes ravis de vous proposer un code de parrainage que vous pouvez partager avec vos amis, votre famille ou vos collègues.</p>\n                                                <p>Lorsqu\'ils utiliseront ce code de parrainage, ils bénéficieront d\'une réduction sur leur premier trajet et vous gagnerez également des récompenses.</p>\n                                                <p>Partagez ce code avec d\'autres et commencez à gagner des récompenses dès aujourd\'hui ! Plus vous parrainez, plus vous pouvez gagner !</p>\n                                                <p>Pour utiliser le code de parrainage, partagez-le simplement avec la personne que vous parrainez, et elle pourra le saisir lors du processus de réservation sur notre application.</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Vous avez gagné avec votre code de parrainage 😊️', 'Nous sommes heureux de vous informer que vous avez gagné de l\'argent avec votre code de parrainage', 'fr', NULL, NULL),
(15, 'cc12aa58-260a-4773-9286-439dafa92ad7', 'Usuario del código de referencia', '<p>Hola {name}</p>\n                                                <p>¡Gracias! Nos complace ofrecerle un código de referencia que puede compartir con sus amigos, familiares o colegas.</p>\n                                                <p>Cuando utilicen este código de referencia, recibirán un descuento en su primer viaje y usted también obtendrá recompensas.</p>\n                                                <p>¡Comparta este código con otras personas y comience a ganar recompensas hoy! ¡Cuanto más recomiendes, más podrás ganar!</p>\n                                                <p>Para usar el código de referencia, simplemente compártelo con la persona que recomiendas y podrá ingresarlo durante el proceso de reserva en nuestra aplicación.</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Has ganado con tu código de referencia 😊️', 'Nos complace informarle que ha ganado dinero con su código de referencia.', 'es', NULL, NULL),
(16, 'cc12aa58-260a-4773-9286-439dafa92ad7', 'مستخدم رمز الإحالة', '<p>مرحبًا {name}</p>\n                                                <p>يشكركم! يسعدنا أن نقدم لك رمز الإحالة الذي يمكنك مشاركته مع أصدقائك أو عائلتك أو زملائك.</p>\n                                                <p>عندما يستخدمون رمز الإحالة هذا، سيحصلون على خصم على رحلتهم الأولى، وستكسب أنت أيضًا مكافآت.</p>\n                                                <p>شارك هذا الرمز مع الآخرين وابدأ في كسب المكافآت اليوم! كلما قمت بالإحالة أكثر، كلما زادت أرباحك!</p>\n                                                <p>لاستخدام رمز الإحالة، ما عليك سوى مشاركته مع الشخص الذي تحيله، ويمكنه إدخاله أثناء عملية الحجز على تطبيقنا.</p>\n                                                <p>أطيب التحيات، </p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'لقد ربحت باستخدام رمز الإحالة الخاص بك 😊️', 'يسعدنا أن نعلمك أنك ربحت المال من خلال رمز الإحالة الخاص بك', 'ar', NULL, NULL),
(17, '8ba95401-d1fc-4693-88e4-d03639453800', 'Wallet Amount Adjusted', '\n                                    <p>Hello {name}</p>\n                                    <p>We are happy to inform you that an amount has been successfully Adjusted to your wallet.</p> \n                                    <p><strong>Transaction Details</strong></p>\n                                    <p><strong>Transaction Id:</strong> {transaction_id}</p>\n                                    <p><strong>Amount:</strong> {currency}{amount}</p>\n                                    <p><strong>Current Balance:</strong>{currency}{current_balance}</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Amount Added Succesfully', 'Amount Credited to Your Wallet Succesfully', 'en', NULL, NULL),
(18, '8ba95401-d1fc-4693-88e4-d03639453800', 'Montant du portefeuille ajusté', '<p>Bonjour {name}</p>\n                                                <p>Nous sommes heureux de vous informer qu\'un montant a été ajusté avec succès à votre portefeuille.</p>\n                                                <p>Détails de la transaction</p>\n                                                <p>Identifiant de transaction: {transaction_id}</p>\n                                                <p>Montante : {currency}{amount}</p>\n                                                <p>Solde actuel: {currency}{current_balance}</p>\n                                                <p>Meilleures salutations, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Montant ajouté avec succès', 'Montant crédité avec succès sur votre portefeuille', 'fr', NULL, NULL),
(19, '8ba95401-d1fc-4693-88e4-d03639453800', 'Monto de billetera ajustado', '<p>Hola {name}</p>\n                                                <p>Nos complace informarle que un monto se ha ajustado exitosamente a su billetera.</p>\n                                                <p>Detalles de la transacción</p>\n                                                <p>ID de transacción: {transaction_id}</p>\n                                                <p>Cantidad: {currency}{amount}</p>\n                                                <p>Saldo actual: {currency}{current_balance}</p>\n                                                <p>Saludos cordiales,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Cantidad agregada exitosamente', 'Monto acreditado en su billetera con éxito', 'es', NULL, NULL),
(20, '8ba95401-d1fc-4693-88e4-d03639453800', 'تم تعديل مبلغ المحفظة', '<p>{مرحبًا {الاسم</p>\n                                                <p>يسعدنا أن نعلمك أنه تم بنجاح تعديل المبلغ إلى محفظتك.</p>\n                                                <p>تفاصيل المعاملة</p>\n                                                <p>معرف المعاملة: {transaction_id}</p>\n                                                <p>كمية: {currency}{amount}</p>\n                                                <p>الرصيد الحالي: {currency}{current_balance}</p>\n                                                <p>مع أطيب التحيات</p>         \n                                                ', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'تمت إضافة المبلغ بنجاح', 'تم إضافة المبلغ إلى محفظتك بنجاح', 'ar', NULL, NULL),
(21, 'b9f740d3-dd78-4fd0-b692-0ffb9f4c27cb', 'Wallet Amount Transfer', '\n                                    <p>Hello {name}</p>\n                                    <p>We are writing to confirm that you have successfully transferred an amount from your wallet.</p>\n                                    <p><strong>Transaction Details</strong></p>\n                                    <p><strong>Transaction Id:</strong> {transaction_id}</p>\n                                    <p><strong>Amount:</strong> {currency}{amount}</p>\n                                    <p><strong>Current Balance:</strong>{currency}{current_balance}</p>\n                                    <p>If you did not initiate this transfer, please contact our support team immediately.</p>\n                                    <p>Thank you for using our services!</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'You Have Received Money', 'You Have Received Money From', 'en', NULL, NULL),
(22, 'b9f740d3-dd78-4fd0-b692-0ffb9f4c27cb', 'Courrier d\'inscription', '<p>Bonjour {name}</p>\n                                                <p>Merci de vous être inscrit auprès de nous, votre application de taxi de confiance. Votre inscription a réussi et nous sommes ravis de vous compter parmi nous.</p>\n                                                <p>Détails de votre compte</p>\n                                                <p>E-mail : {email}</p>\n                                                <p>Numéro de mobile : {mobile}</p>\n                                                <p>Nous sommes maintenant prêts à vous aider avec vos besoins de transport ! Pour commencer, cliquez simplement sur le bouton ci-dessous pour vous connecter à votre compte :</p> \n                                                <p>Meilleures salutations, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Titre de notification en français', 'Corps de notification en français', 'fr', NULL, NULL),
(23, 'b9f740d3-dd78-4fd0-b692-0ffb9f4c27cb', 'Correo de registro', '<p>Hola {name}</p>\n                                                <p>Gracias por registrarte con nosotros, tu aplicación de taxis de confianza. Su registro fue exitoso y estamos emocionados de tenerlo a bordo.</p>\n                                                <p>Detalles de su cuenta</p>\n                                                <p>Correo electrónico: {email}</p>\n                                                <p>Número de móvil: {mobile}</p>\n                                                <p>¡Ahora estamos listos para ayudarle con sus necesidades de transporte! Para comenzar, simplemente haga clic en el botón a continuación para iniciar sesión en su cuenta:</p> \n                                                <p>Saludos cordiales,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Título de la notificación en español', 'Cuerpo de la notificación en español', 'es', NULL, NULL),
(24, 'b9f740d3-dd78-4fd0-b692-0ffb9f4c27cb', 'بريد التسجيل', '<p>{مرحبًا {الاسم</p>\n                                                <p>نشكرك على الاشتراك معنا، تطبيق سيارات الأجرة الموثوق به. تم تسجيلك بنجاح، ونحن متحمسون لانضمامك إلينا.</p>\n                                                <p>تفاصيل حسابك</p>\n                                                <p>البريد الإلكتروني: {email}</p>\n                                                <p>رقم الجوال: {mobile}</p>\n                                                <p>نحن الآن على استعداد لمساعدتك في تلبية احتياجات النقل الخاصة بك! للبدء، ما عليك سوى النقر على الزر أدناه لتسجيل الدخول إلى حسابك:</p> \n                                                <p>مع أطيب التحيات</p>         \n                                                ', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'Benachrichtigungstitel auf Deutsch', 'Benachrichtigungstext auf Deutsch', 'ar', NULL, NULL),
(25, 'b9db6b5a-57f8-4095-b6d9-6b1d7a3172f2', 'Account Approval', '\n                                    <p>Congratulations,{name} </p>\n                                    <p>We are happy to inform you that your user account has been successfully approved. Start exploring the app and enjoy a seamless experience...</p>   \n                                    <p>Please log in to your account using the credentials provided during registration. If you encounter any issues, feel free to reach out to our support team.</p>        \n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'Button', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Account Approved 😃️', 'Your profile verified and approved', 'en', NULL, NULL),
(26, 'b9db6b5a-57f8-4095-b6d9-6b1d7a3172f2', 'Approbation du compte', '<p>Félicitations, {name}</p>\n                                                <p>Nous sommes heureux de vous informer que votre compte utilisateur a été approuvé avec succès. Commencez à explorer l’application et profitez d’une expérience fluide..</p>\n                                                <p>Veuillez vous connecter à votre compte en utilisant les identifiants fournis lors de l\'inscription. Si vous rencontrez des problèmes, n\'hésitez pas à contacter notre équipe d\'assistance.</p>\n                                                <p>Meilleures salutations, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Compte approuvé 😃️', 'Votre profil vérifié et approuvé', 'fr', NULL, NULL),
(27, 'b9db6b5a-57f8-4095-b6d9-6b1d7a3172f2', 'Aprobación de cuenta', '<p>Felicidades, {name}</p>\n                                                <p>Nos complace informarle que su cuenta de usuario ha sido aprobada con éxito. Comience a explorar la aplicación y disfrute de una experiencia fluida...</p>\n                                                <p>Inicie sesión en su cuenta utilizando las credenciales proporcionadas durante el registro. Si tiene algún problema, no dude en comunicarse con nuestro equipo de soporte.</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Bouton', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Cuenta aprobada 😃️', 'Tu perfil verificado y aprobado', 'es', NULL, NULL),
(28, 'b9db6b5a-57f8-4095-b6d9-6b1d7a3172f2', 'تقدير الحساب', '<p>تهنئة, {name}</p>\n                                                <p>يسعدنا إعلامكم بأنه قد تمت الموافقة على حساب المستخدم الخاص بكم بنجاح. ابدأوا استكشاف التطبيق واستمتعوا بتجربة سلسة...</p>\n                                                <p>يرجى تسجيل الدخول إلى حسابك باستخدام بيانات الاعتماد المقدمة أثناء التسجيل. إذا واجهت أي مشاكل، فلا تتردد في التواصل مع فريق الدعم لدينا.</p>\n                                                <p>أطيب التحيات, </p>         \n                                                <p>برامج إم آي</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'تمت الموافقة على الحساب 😃️', 'تم التحقق من ملفك الشخصي والموافقة عليه', 'ar', NULL, NULL),
(29, '64bdd2b5-8b63-4bc3-bdb7-9a252ef54334', 'Account Disapproval', '\n                                    <p>Hello {name}</p>\n                                    <p> We regret to inform you that your application to become a user with our taxi service has not been approved at this time.</p>   \n                                    <p>If you have any questions or need further clarification, feel free to contact our support team.</p>        \n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'Button', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Account Declined 🙁️', 'Your Account declined due to some reason. please contact our admin', 'en', NULL, NULL),
(30, '64bdd2b5-8b63-4bc3-bdb7-9a252ef54334', 'Refus du compte', '<p>Bonjour, {name}</p>\n                                                <p>Nous avons le regret de vous informer que votre demande pour devenir utilisateur auprès de notre service de taxi n\'a pas été approuvée pour le moment.</p>\n                                                <p>Si vous avez des questions ou avez besoin de précisions supplémentaires, n\'hésitez pas à contacter notre équipe d\'assistance.</p>\n                                                <p>Meilleures salutations, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Compte refusé 🙁️', 'Votre compte a été refusé pour une raison quelconque. veuillez contacter notre administrateur', 'fr', NULL, NULL),
(31, '64bdd2b5-8b63-4bc3-bdb7-9a252ef54334', 'Rechazo de cuenta', '<p>Hola, {name}</p>\n                                                <p>Lamentamos informarle que su solicitud para convertirse en usuario de nuestro servicio de taxis no ha sido aprobada en este momento.</p>\n                                                <p>Si tiene alguna pregunta o necesita más aclaraciones, no dude en ponerse en contacto con nuestro equipo de soporte.</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Bouton', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Cuenta rechazada 🙁️', 'Su cuenta fue rechazada por algún motivo. por favor contacte a nuestro administrador', 'es', NULL, NULL),
(32, '64bdd2b5-8b63-4bc3-bdb7-9a252ef54334', 'رفض الحساب', '<p>مرحبًا {name}</p>\n                                                <p> يؤسفنا إبلاغكم بأن طلبكم للانضمام كمستخدم لخدمة سيارات الأجرة لدينا لم تتم الموافقة عليه في الوقت الحالي.</p>\n                                                <p>إذا كان لديك أي أسئلة أو كنت بحاجة إلى مزيد من التوضيح، فلا تتردد في الاتصال بفريق الدعم لدينا.</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'الحساب مرفوض 🙁️', 'لقد تم رفض حسابك لسبب ما. يرجى الاتصال المشرف لدينا', 'ar', NULL, NULL),
(33, 'f81dc493-a420-4a2f-93c5-fa2583303b30', 'Document Expired', '\n                                    <p>Hello {name}</p>\n                                    <p>Document Expired, Kindly Update your documents</p>\n                                     <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'Share', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Document Expires', 'Document Expired', 'en', NULL, NULL),
(34, 'f81dc493-a420-4a2f-93c5-fa2583303b30', 'Document expiré', '<p>Bonjour {name}</p>\n                                                <p>Document expiré, veuillez mettre à jour vos documents</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Le document expire', 'Document expiré', 'fr', NULL, NULL),
(35, 'f81dc493-a420-4a2f-93c5-fa2583303b30', 'Documento caducado', '<p>Hola {name}</p>\n                                                <p>Documento vencido, por favor actualice sus documentos</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'El documento vence', 'Documento caducado', 'es', NULL, NULL),
(36, 'f81dc493-a420-4a2f-93c5-fa2583303b30', 'انتهت صلاحية الوثيقة', '<p>مرحبًا {name}</p>\n                                                <p>انتهت صلاحية الوثيقة، يرجى تحديث المستندات الخاصة بك</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'انتهاء صلاحية المستند', 'انتهت صلاحية الوثيقة', 'ar', NULL, NULL),
(37, '037b7e02-8273-4cf6-bf8b-181dfe110807', 'Ride Remainder', '\n                                    <p>Hello {name}</p>\n                                    <p>To get a Ride, Open the app</p>\n                                     <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'Share', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Gentle Reminder 😊️', 'Please open the App to get ride requests', 'en', NULL, NULL),
(38, '037b7e02-8273-4cf6-bf8b-181dfe110807', 'Document expiré', '<p>Bonjour {name}</p>\n                                                <p>Document expiré, veuillez mettre à jour vos documents</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Doux rappel 😊️', 'Veuillez ouvrir l\'application pour recevoir des demandes de trajet', 'fr', NULL, NULL),
(39, '037b7e02-8273-4cf6-bf8b-181dfe110807', 'Documento caducado', '<p>Hola {name}</p>\n                                                <p>Documento vencido, por favor actualice sus documentos</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Recordatorio gentil 😊️', 'Abra la aplicación para recibir solicitudes de viaje.', 'es', NULL, NULL),
(40, '037b7e02-8273-4cf6-bf8b-181dfe110807', 'انتهت صلاحية الوثيقة', '<p>مرحبًا {name}</p>\n                                                <p>انتهت صلاحية الوثيقة، يرجى تحديث المستندات الخاصة بك</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'تذكير لطيف 😊️', 'يرجى فتح التطبيق للحصول على طلبات الركوب', 'ar', NULL, NULL),
(41, '9ba09942-dcb5-4146-b3f3-ad0194150bcf', 'Account Approval', '\n                                    <p>Congratulations,{name} </p>\n                                    <p>We are  to inform you that your driver account  has been successfully approved. You are now ready to start accepting ride requests and earning..</p>   \n                                    <p>Please log in to your account using the credentials provided during registration. If you encounter any issues, feel free to reach out to our support team.</p>        \n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'Button', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Account Approved 😃️', 'Your profile verified and approved', 'en', NULL, NULL),
(42, '9ba09942-dcb5-4146-b3f3-ad0194150bcf', 'Approbation du compte', '<p>Félicitations, {name}</p>\n                                                <p>Nous devons vous informer que votre compte chauffeur a été approuvé avec succès. Vous êtes maintenant prêt à commencer à accepter des demandes de courses et à gagner des revenus.</p>\n                                                <p>Veuillez vous connecter à votre compte en utilisant les identifiants fournis lors de l\'inscription. Si vous rencontrez des problèmes, n\'hésitez pas à contacter notre équipe d\'assistance.</p>\n                                                <p>Meilleures salutations, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Compte approuvé 😃️', 'Votre profil vérifié et approuvé', 'fr', NULL, NULL),
(43, '9ba09942-dcb5-4146-b3f3-ad0194150bcf', 'Aprobación de cuenta', '<p>Felicidades, {name}</p>\n                                                <p>Le informamos que su cuenta de conductor ha sido aprobada exitosamente. Ahora está listo para comenzar a aceptar solicitudes de viaje y ganar dinero.</p>\n                                                <p>Inicie sesión en su cuenta utilizando las credenciales proporcionadas durante el registro. Si tiene algún problema, no dude en comunicarse con nuestro equipo de soporte.</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Bouton', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Cuenta aprobada 😃️', 'Tu perfil verificado y aprobado', 'es', NULL, NULL),
(44, '9ba09942-dcb5-4146-b3f3-ad0194150bcf', 'تقدير الحساب', '<p>تهنئة, {name}</p>\n                                                <p>نود أن نعلمك أنه تمت الموافقة على حساب السائق الخاص بك بنجاح. أنت الآن جاهز للبدء في قبول طلبات الرحلات وتحقيق الربح..</p>\n                                                <p>يرجى تسجيل الدخول إلى حسابك باستخدام بيانات الاعتماد المقدمة أثناء التسجيل. إذا واجهت أي مشاكل، فلا تتردد في التواصل مع فريق الدعم لدينا.</p>\n                                                <p>أطيب التحيات, </p>         \n                                                <p>برامج إم آي</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'تمت الموافقة على الحساب 😃️', 'تم التحقق من ملفك الشخصي والموافقة عليه', 'ar', NULL, NULL),
(45, '3a46ac8b-f64c-40c4-85ee-39827484e0ee', 'Account Disapproval', '\n                                    <p>Hello {name}</p>\n                                    <p> We regret to inform you that your application to become a driver with our taxi service has not been approved at this time.</p>   \n                                    <p>If you have any questions or need further clarification, feel free to contact our support team.</p>        \n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'Button', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Account Declined 🙁️', 'Your Account declined due to some reason. please contact our admin', 'en', NULL, NULL),
(46, '3a46ac8b-f64c-40c4-85ee-39827484e0ee', 'Refus du compte', '<p>Bonjour, {name}</p>\n                                                <p>Nous avons le regret de vous informer que votre demande pour devenir chauffeur auprès de notre service de taxi n\'a pas été approuvée pour le moment.</p>\n                                                <p>Si vous avez des questions ou avez besoin de précisions supplémentaires, n\'hésitez pas à contacter notre équipe d\'assistance.</p>\n                                                <p>Meilleures salutations, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Compte refusé 🙁️', 'Votre compte a été refusé pour une raison quelconque. veuillez contacter notre administrateur', 'fr', NULL, NULL),
(47, '3a46ac8b-f64c-40c4-85ee-39827484e0ee', 'Rechazo de cuenta', '<p>Hola, {name}</p>\n                                                <p>Lamentamos informarle que su solicitud para convertirse en conductor de nuestro servicio de taxi no ha sido aprobada en este momento.</p>\n                                                <p>Si tiene alguna pregunta o necesita más aclaraciones, no dude en ponerse en contacto con nuestro equipo de soporte.</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Bouton', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Cuenta rechazada 🙁️', 'Su cuenta fue rechazada por algún motivo. por favor contacte a nuestro administrador', 'es', NULL, NULL),
(48, '3a46ac8b-f64c-40c4-85ee-39827484e0ee', 'رفض الحساب', '<p>مرحبًا {name}</p>\n                                                <pنأسف لإبلاغك بأن طلبك لتصبح سائقًا مع خدمة سيارات الأجرة لدينا لم تتم الموافقة عليه في الوقت الحالي.</p>\n                                                <p>إذا كان لديك أي أسئلة أو كنت بحاجة إلى مزيد من التوضيح، فلا تتردد في الاتصال بفريق الدعم لدينا.</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'الحساب مرفوض 🙁️', 'لقد تم رفض حسابك لسبب ما. يرجى الاتصال المشرف لدينا', 'ar', NULL, NULL),
(49, 'c5d56a58-dd6a-4459-980d-4fa4a8a55178', 'Wallet Amount Adjusted', '\n                                    <p>Hello {name}</p>\n                                    <p>We are happy to inform you that an amount has been successfully Adjusted to your wallet.</p>  \n                                    <p><strong>Transaction Details</strong></p>\n                                    <p><strong>Transaction Id:</strong> {transaction_id}</p>\n                                    <p><strong>Amount:</strong> {currency}{amount}</p>\n                                    <p><strong>Current Balance:</strong>{currency}{current_balance}</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Amount Added Succesfully', 'Amount Credited to Your Wallet Succesfully', 'en', NULL, NULL),
(50, 'c5d56a58-dd6a-4459-980d-4fa4a8a55178', 'Montant du portefeuille ajusté', '<p>Bonjour {name}</p>\n                                                <p>Nous sommes heureux de vous informer qu\'un montant a été ajusté avec succès à votre portefeuille.</p>\n                                                <p>Détails de la transaction</p>\n                                                <p>Identifiant de transaction: {transaction_id}</p>\n                                                <p>Montante : {currency}{amount}</p>\n                                                <p>Solde actuel: {currency}{current_balance}</p>\n                                                <p>Meilleures salutations, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Montant ajouté avec succès', 'Montant crédité avec succès sur votre portefeuille', 'fr', NULL, NULL),
(51, 'c5d56a58-dd6a-4459-980d-4fa4a8a55178', 'Monto de billetera ajustado', '<p>Hola {name}</p>\n                                                <p>Nos complace informarle que un monto se ha ajustado exitosamente a su billetera.</p>\n                                                <p>Detalles de la transacción</p>\n                                                <p>ID de transacción: {transaction_id}</p>\n                                                <p>Cantidad: {currency}{amount}</p>\n                                                <p>Saldo actual: {currency}{current_balance}</p>\n                                                <p>Saludos cordiales,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Cantidad agregada exitosamente', 'Monto acreditado en su billetera con éxito', 'es', NULL, NULL),
(52, 'c5d56a58-dd6a-4459-980d-4fa4a8a55178', 'تم تعديل مبلغ المحفظة', '<p>{مرحبًا {الاسم</p>\n                                                <p>يسعدنا أن نعلمك أنه تم بنجاح تعديل المبلغ إلى محفظتك.</p>\n                                                <p>تفاصيل المعاملة</p>\n                                                <p>معرف المعاملة: {transaction_id}</p>\n                                                <p>كمية: {currency}{amount}</p>\n                                                <p>الرصيد الحالي: {currency}{current_balance}</p>\n                                                <p>مع أطيب التحيات</p>         \n                                                ', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'تمت إضافة المبلغ بنجاح', 'تم إضافة المبلغ إلى محفظتك بنجاح', 'ar', NULL, NULL),
(53, '5f8710e0-74bc-4bda-a45b-7dcf4af889ce', 'Withdrawal Request Approval', '\n                                    <p>Hello {name}</p>\n                                    <p>  Your withdrawal request has been approved. Here are the details:.</p>                                    \n                                    <p><strong>Transaction Details</strong></p>\n                                    <p><strong>Transaction Id:</strong> {transaction_id}</p>\n                                    <p><strong>Amount:</strong> {currency}{amount}</p>\n                                    <p><strong>Current Balance:</strong>{currency}{current_balance}</p>\n                                    <p>If you have any issues with payment, kindly reply to this email or send an email to support@gmail.com</p>\n                                    <p>Thank you for using our services!</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Payment Credited 😃️', 'Your Payment Credited To Your Given Account', 'en', NULL, NULL),
(54, '5f8710e0-74bc-4bda-a45b-7dcf4af889ce', 'Approbation de la demande de retrait', '<p>Bonjour {name}</p>\n                                                <p>Détails de la transaction</p>\n                                                <p>ID de transaction : {transaction_id}</p>\n                                                <p>Montant:{currency}{amount}</p>\n                                                <p>Solde actuel: {currency}{current_balance}</p>\n                                                <p>Si vous rencontrez des problèmes avec le paiement, veuillez répondre à cet e-mail ou envoyer un e-mail à support@gmail.com</p>\n                                                <p>Merci d\'utiliser nos services !</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Paiement crédité 😃️', 'Votre paiement crédité sur votre compte donné', 'fr', NULL, NULL);
INSERT INTO `notification_channels_translations` (`id`, `notification_channel_id`, `email_subject`, `mail_body`, `button_name`, `footer_content`, `footer_copyrights`, `push_title`, `push_body`, `locale`, `created_at`, `updated_at`) VALUES
(55, '5f8710e0-74bc-4bda-a45b-7dcf4af889ce', 'Aprobación de solicitud de retiro', '<p>Hola {name}</p>\n                                                <p>Su solicitud de retiro ha sido aprobada. Aquí están los detalles:.</p>\n                                                <p>Detalles de la transacción</p>\n                                                <p>ID de transacción: {transaction_id}</p>\n                                                <p>Monto: {currency}{amount}</p>\n                                                <p>Saldo actual:{currency}{current_balance}</p>\n                                                <p>Si tiene algún problema con el pago, responda amablemente a este correo electrónico o envíe un correo electrónico a support@gmail.com</p>\n                                                <p>¡Gracias por utilizar nuestros servicios!</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Pago acreditado 😃️', 'Su pago acreditado a su cuenta dada', 'es', NULL, NULL),
(56, '5f8710e0-74bc-4bda-a45b-7dcf4af889ce', 'رفض طلب السحب', '<p>مرحبًا {name}</p>\n                                                <p>للأسف، تم رفض طلب السحب الخاص بك.</p>\n                                                <p>إذا كانت لديك أية مشكلات تتعلق بالدفع، فيرجى الرد على هذا البريد الإلكتروني أو إرسال بريد إلكتروني إلى support@gmail.com</p>\n                                                <p>شكرا لك على استخدام خدماتنا!</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'تم رفض الدفع', 'تم رفض الدفع الخاص بك', 'ar', NULL, NULL),
(57, '755f92ef-e876-4ca1-bd39-846a7a1d5dcc', 'Withdrawal Request Decline', '\n                                    <p>Hello {name}</p>\n                                    <p>Unfortunately, your withdrawal request has been declined.</p>   \n                                    <p>If you have any issues with payment, kindly reply to this email or send an email to support@gmail.com</p>\n                                    <p>Thank you for using our services!</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Payment Declained ', 'Your Payment Declained', 'en', NULL, NULL),
(58, '755f92ef-e876-4ca1-bd39-846a7a1d5dcc', 'Refus de la demande de retrait', '<p>Bonjour {name}</p>\n                                                <p>Malheureusement, votre demande de retrait a été refusée.</p>\n                                                <p>Si vous rencontrez des problèmes avec le paiement, veuillez répondre à cet e-mail ou envoyer un e-mail à support@gmail.com</p>\n                                                <p>Merci d\'utiliser nos services !</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Paiement refusé', 'Votre paiement refusé', 'fr', NULL, NULL),
(59, '755f92ef-e876-4ca1-bd39-846a7a1d5dcc', 'Rechazo de solicitud de retiro', '<p>Hola {name}</p>\n                                                <p>Lamentablemente, su solicitud de retiro ha sido rechazada.</p>\n                                                <p>Si tiene algún problema con el pago, responda amablemente a este correo electrónico o envíe un correo electrónico a support@gmail.com</p>\n                                                <p>¡Gracias por utilizar nuestros servicios!</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Pago rechazado', 'Su pago rechazado', 'es', NULL, NULL),
(60, '755f92ef-e876-4ca1-bd39-846a7a1d5dcc', 'بريد التسجيل', '<p>{مرحبًا {الاسم</p>\n                                                <p>نشكرك على الاشتراك معنا، تطبيق سيارات الأجرة الموثوق به. تم تسجيلك بنجاح، ونحن متحمسون لانضمامك إلينا.</p>\n                                                <p>تفاصيل حسابك</p>\n                                                <p>البريد الإلكتروني: {email}</p>\n                                                <p>رقم الجوال: {mobile}</p>\n                                                <p>نحن الآن على استعداد لمساعدتك في تلبية احتياجات النقل الخاصة بك! للبدء، ما عليك سوى النقر على الزر أدناه لتسجيل الدخول إلى حسابك:</p> \n                                                <p>مع أطيب التحيات</p>         \n                                                ', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'Benachrichtigungstitel auf Deutsch', 'Benachrichtigungstext auf Deutsch', 'ar', NULL, NULL),
(61, '2c4667de-2b44-4760-9a30-9c94a7342247', 'Invoice For Ride', '\n                                    <p>Hello {name}</p>\n                                    <p>Thank You for Riding with us</p>\n                                    <p><strong>Here is the summary of your recent trip: <strong></p>', 'Reset Password', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Invoice Downloaded successfully', 'Invoice Downloaded successfully', 'en', NULL, NULL),
(62, '2c4667de-2b44-4760-9a30-9c94a7342247', 'Facture pour le trajet', '<p>Bonjour {name}</p>\n                                                <p>Merci d\'avoir roulé avec nous</p>\n                                                <p>Voici le résumé de votre récent voyage :</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Chauffeur A terminé le voyage', 'Le chauffeur a terminé le trajet. Aidez-nous en évaluant le chauffeur.', 'fr', NULL, NULL),
(63, '2c4667de-2b44-4760-9a30-9c94a7342247', 'Factura por viaje', '<p>Hola {name}</p>\n                                                <p>Gracias por viajar con nosotros</p>\n                                                <p>Aquí está el resumen de su reciente viaje</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'El conductor finalizó el viaje.', 'El conductor terminó el viaje. Ayúdenos calificando al conductor.', 'es', NULL, NULL),
(64, '2c4667de-2b44-4760-9a30-9c94a7342247', 'فاتورة للركوب', '<p>مرحبًا {name}</p>\n                                                <p>شكرا لركوبك معنا</p>\n                                                <p>فيما يلي ملخص رحلتك الأخيرة:</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'أنهى السائق الرحلة', 'أنهى السائق الرحلة، الرجاء مساعدتنا بتقييم السائق', 'ar', NULL, NULL),
(65, 'a6b30ce4-78f1-4ecf-b272-e20c204d7d45', 'Trip Cancelled', '\n                                    <p>Hello {name}</p>\n                                    <p>Trip Cancelled</p>', 'Reset Password', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Trip Cancelled By Customer 🙁️', 'The customer cancelled the ride,please wait for another ride', 'en', NULL, NULL),
(66, 'a6b30ce4-78f1-4ecf-b272-e20c204d7d45', 'Voyage annulé par le client', '<p>Bonjour {name}</p>\n                                                <p>Malheureusement, votre demande de retrait a été refusée.</p>\n                                                <p>Si vous rencontrez des problèmes avec le paiement, veuillez répondre à cet e-mail ou envoyer un e-mail à support@gmail.com</p>\n                                                <p>Merci d\'utiliser nos services !</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Voyage annulé par le client', 'Le client a annulé le trajet, veuillez attendre un autre trajet', 'fr', NULL, NULL),
