(104, 'a42b2a0b-208b-4531-b152-9cd9afa4b105', 'تم تحويل نقاط المكافأة ', '<p>مرحبًا {name}</p>\n                                                <p>للأسف، تم رفض طلب السحب الخاص بك.</p>\n                                                <p>إذا كانت لديك أية مشكلات تتعلق بالدفع، فيرجى الرد على هذا البريد الإلكتروني أو إرسال بريد إلكتروني إلى support@gmail.com</p>\n                                                <p>شكرا لك على استخدام خدماتنا!</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'تم تحويل نقاط المكافأة 😃️', 'نقاط المكافأة الخاصة بك تضاف إلى حسابك', 'ar', NULL, NULL),
(105, '7cb1a260-6a93-41a0-a9dd-bb1c2319b19b', 'Transaction Failed', '\n                                    <p>Hello {name}</p>\n                                    <p>We are writing to confirm that you have successfully transferred an amount from your wallet.</p>\n                                    <p><strong>Transaction Details</strong></p>\n                                    <p><strong>Transaction Id:</strong> {transaction_id}</p>\n                                    <p><strong>Amount:</strong> {currency}{amount}</p>\n                                    <p><strong>Current Balance:</strong>{currency}{current_balance}</p>\n                                    <p>If you did not initiate this transfer, please contact our support team immediately.</p>\n                                    <p>Thank you for using our services!</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Transaction Failed', 'Transaction Failed', 'en', NULL, NULL),
(106, '7cb1a260-6a93-41a0-a9dd-bb1c2319b19b', 'Échec de la transaction', '<p>Bonjour {name}</p>\n                                                <p>Malheureusement, votre demande de retrait a été refusée.</p>\n                                                <p>Si vous rencontrez des problèmes avec le paiement, veuillez répondre à cet e-mail ou envoyer un e-mail à support@gmail.com</p>\n                                                <p>Merci d\'utiliser nos services !</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Échec de la transaction', 'Échec de la transaction', 'fr', NULL, NULL),
(107, '7cb1a260-6a93-41a0-a9dd-bb1c2319b19b', 'Transacción fallida', '<p>Hola {name}</p>\n                                                <p>Lamentablemente, su solicitud de retiro ha sido rechazada.</p>\n                                                <p>Si tiene algún problema con el pago, responda amablemente a este correo electrónico o envíe un correo electrónico a support@gmail.com</p>\n                                                <p>¡Gracias por utilizar nuestros servicios!</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Transacción fallida', 'Transacción fallida', 'es', NULL, NULL),
(108, '7cb1a260-6a93-41a0-a9dd-bb1c2319b19b', 'فشلت الصفقة', '<p>مرحبًا {name}</p>\n                                                <p>للأسف، تم رفض طلب السحب الخاص بك.</p>\n                                                <p>إذا كانت لديك أية مشكلات تتعلق بالدفع، فيرجى الرد على هذا البريد الإلكتروني أو إرسال بريد إلكتروني إلى support@gmail.com</p>\n                                                <p>شكرا لك على استخدام خدماتنا!</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'فشلت الصفقة', 'فشلت الصفقة', 'ar', NULL, NULL),
(109, '6f5d6e64-5251-4db5-b35d-f62f24096b2e', 'Payment Received', '\n                                    <p>Hello {name}</p>\n                                    <p>We are writing to confirm that you have successfully transferred an amount from your wallet.</p>\n                                    <p><strong>Transaction Details</strong></p>\n                                    <p><strong>Transaction Id:</strong> {transaction_id}</p>\n                                    <p><strong>Amount:</strong> {currency}{amount}</p>\n                                    <p><strong>Current Balance:</strong>{currency}{current_balance}</p>\n                                    <p>If you did not initiate this transfer, please contact our support team immediately.</p>\n                                    <p>Thank you for using our services!</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Payment Received', 'Payment Received from customer', 'en', NULL, NULL),
