(128, '892ddb5f-6701-4515-9716-8a6c8ad87524', 'بدأت الرحلة', '<p>مرحبًا {name}</p>\n                                                <p>للأسف، تم رفض طلب السحب الخاص بك.</p>\n                                                <p>إذا كانت لديك أية مشكلات تتعلق بالدفع، فيرجى الرد على هذا البريد الإلكتروني أو إرسال بريد إلكتروني إلى support@gmail.com</p>\n                                                <p>شكرا لك على استخدام خدماتنا!</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'بدأت الرحلة', 'بدأت الرحلة نحو موقع الهبوط', 'ar', NULL, NULL),
(129, '55b749c0-ca59-4306-a205-f1ada1ba831a', 'Trip Request Accepted', '\n                                    <p>Hello {name}</p>\n                                    <p>We are writing to confirm that you have successfully transferred an amount from your wallet.</p>\n                                    <p><strong>Transaction Details</strong></p>\n                                    <p><strong>Transaction Id:</strong> {transaction_id}</p>\n                                    <p><strong>Amount:</strong> {currency}{amount}</p>\n                                    <p><strong>Current Balance:</strong>{currency}{current_balance}</p>\n                                    <p>If you did not initiate this transfer, please contact our support team immediately.</p>\n                                    <p>Thank you for using our services!</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Trip Request Accepted', 'The Driver is coming to pick you', 'en', NULL, NULL),
(130, '55b749c0-ca59-4306-a205-f1ada1ba831a', 'Demande de voyage acceptée', '<p>Bonjour {name}</p>\n                                                <p>Malheureusement, votre demande de retrait a été refusée.</p>\n                                                <p>Si vous rencontrez des problèmes avec le paiement, veuillez répondre à cet e-mail ou envoyer un e-mail à support@gmail.com</p>\n                                                <p>Merci d\'utiliser nos services !</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Demande de voyage acceptée', 'Le Chauffeur vient vous chercher', 'fr', NULL, NULL),
(131, '55b749c0-ca59-4306-a205-f1ada1ba831a', 'Solicitud de viaje aceptada', '<p>Hola {name}</p>\n                                                <p>Lamentablemente, su solicitud de retiro ha sido rechazada.</p>\n                                                <p>Si tiene algún problema con el pago, responda amablemente a este correo electrónico o envíe un correo electrónico a support@gmail.com</p>\n                                                <p>¡Gracias por utilizar nuestros servicios!</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Solicitud de viaje aceptada', 'El conductor viene a recogerte.', 'es', NULL, NULL),
(132, '55b749c0-ca59-4306-a205-f1ada1ba831a', 'لم يتم العثور على برنامج التشغيل', '<p>مرحبًا {name}</p>\n                                                <p>للأسف، تم رفض طلب السحب الخاص بك.</p>\n                                                <p>إذا كانت لديك أية مشكلات تتعلق بالدفع، فيرجى الرد على هذا البريد الإلكتروني أو إرسال بريد إلكتروني إلى support@gmail.com</p>\n                                                <p>شكرا لك على استخدام خدماتنا!</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'تم قبول طلب الرحلة', 'السائق قادم لاصطحابك', 'ar', NULL, NULL),
(133, '0c551900-77b3-435e-895d-1736f6770666', 'Driver not Found', '\n                                    <p>Hello {name}</p>\n                                    <p>We are writing to confirm that you have successfully transferred an amount from your wallet.</p>\n                                    <p><strong>Transaction Details</strong></p>\n                                    <p><strong>Transaction Id:</strong> {transaction_id}</p>\n                                    <p><strong>Amount:</strong> {currency}{amount}</p>\n                                    <p><strong>Current Balance:</strong>{currency}{current_balance}</p>\n                                    <p>If you did not initiate this transfer, please contact our support team immediately.</p>\n                                    <p>Thank you for using our services!</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'No Driver Found Around You 🙁️', 'Sorry plese try again after some times,there is no driver available for your ride now', 'en', NULL, NULL),
(134, '0c551900-77b3-435e-895d-1736f6770666', 'Pilote introuvable', '<p>Bonjour {name}</p>\n                                                <p>Malheureusement, votre demande de retrait a été refusée.</p>\n                                                <p>Si vous rencontrez des problèmes avec le paiement, veuillez répondre à cet e-mail ou envoyer un e-mail à support@gmail.com</p>\n                                                <p>Merci d\'utiliser nos services !</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Logiciels MI</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 et droits réservés', 'Aucun chauffeur trouvé autour de vous 🙁️', 'Désolé, veuillez réessayer après quelques instants. Aucun chauffeur n\'est disponible pour votre trajet pour le moment.', 'fr', NULL, NULL),
(135, '0c551900-77b3-435e-895d-1736f6770666', 'Controlador no encontrado', '<p>Hola {name}</p>\n                                                <p>Lamentablemente, su solicitud de retiro ha sido rechazada.</p>\n                                                <p>Si tiene algún problema con el pago, responda amablemente a este correo electrónico o envíe un correo electrónico a support@gmail.com</p>\n                                                <p>¡Gracias por utilizar nuestros servicios!</p>\n                                                <p>Atentamente,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'No se encontró ningún conductor a tu alrededor 🙁️', 'Lo sentimos, inténtelo de nuevo después de algunas veces. No hay ningún conductor disponible para su viaje en este momento.', 'es', NULL, NULL),
(136, '0c551900-77b3-435e-895d-1736f6770666', 'لم يتم العثور على برنامج التشغيل', '<p>مرحبًا {name}</p>\n                                                <p>للأسف، تم رفض طلب السحب الخاص بك.</p>\n                                                <p>إذا كانت لديك أية مشكلات تتعلق بالدفع، فيرجى الرد على هذا البريد الإلكتروني أو إرسال بريد إلكتروني إلى support@gmail.com</p>\n                                                <p>شكرا لك على استخدام خدماتنا!</p>\n                                                <p>أطيب التحيات،</p>         \n                                                <p>برامج MI</p>', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'لم يتم العثور على سائق من حولك 🙁️', 'عذرًا، يرجى المحاولة مرة أخرى بعد مرور بعض الوقت، لا يوجد سائق متاح لرحلتك الآن', 'ar', NULL, NULL),
