(151, 'bfb49559-cae2-4a1b-b509-2be6996d5231', 'Nuevo mensaje de chat', '<p>Hola {name}</p>\n                                                <p>Nuevo mensaje de chat</p> \n                                                <p>Saludos cordiales,</p>         \n                                                <p>Software MI</p>', 'Botón', '<p>Si tiene alguna consulta, envíenos un correo electrónico a support@gmail.com. Ellos responderán la pregunta y lo ayudarán.</p>', '2021 Missoftwares y derechos reservados', 'Nuevo mensaje de chat', 'Nuevo mensaje de chat', 'es', NULL, NULL),
(152, 'bfb49559-cae2-4a1b-b509-2be6996d5231', 'رسالة دردشة جديدة', '<p>{مرحبًا {الاسم</p>\n                                                <p>نشكرك على الاشتراك معنا، تطبيق سيارات الأجرة الموثوق به. تم تسجيلك بنجاح، ونحن متحمسون لانضمامك إلينا.</p>\n                                                <p>تفاصيل حسابك</p>\n                                                <p>البريد الإلكتروني: {email}</p>\n                                                <p>رقم الجوال: {mobile}</p>\n                                                <p>نحن الآن على استعداد لمساعدتك في تلبية احتياجات النقل الخاصة بك! للبدء، ما عليك سوى النقر على الزر أدناه لتسجيل الدخول إلى حسابك:</p> \n                                                <p>مع أطيب التحيات</p>         \n                                                ', 'زر', '<p>إذا كانت لديك أية استفسارات، يرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. وسوف يجيبون على السؤال ويساعدونك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'رسالة دردشة جديدة', 'رسالة دردشة جديدة', 'ar', NULL, NULL),
(153, '285d3e51-1c0e-47c2-afc7-63d4e3d5bf63', 'Change Drop Destination', '\n                                    <p>Hello {name}</p>\n                                    <p>The drop location has been changed</p>\n                                    <p>Thank you for using our services!</p>\n                                    <p>Best regards, </p>         \n                                    <p>Sangvish</p>', 'View Details', '<p>If you have any queries , Please email us support@gmail.com.They will answer the question and help you out.</p>', '2021 Sangvish & Rights Reserved', 'Drop has been changed', 'Drop has been changed', 'en', NULL, NULL),
(154, '285d3e51-1c0e-47c2-afc7-63d4e3d5bf63', 'Changer la destination de dépôt', '<p>Bonjour {name}</p>\n                                                <p>La destination a été modifiée</p>\n                                                <p>Merci d\'utiliser nos services !</p>\n                                                <p>Cordialement, </p>         \n                                                <p>Sangvish</p>', 'Bouton', '<p>Si vous avez des questions, veuillez nous envoyer un e-mail à support@gmail.com. Ils répondront à la question et vous aideront.</p>', 'Sangvish 2021 & Droits réservés', 'Le drop a été modifié', 'La destination de dépôt a été modifiéeyy', 'fr', NULL, NULL),
(155, '285d3e51-1c0e-47c2-afc7-63d4e3d5bf63', 'Cambiar destino de entrega', '<p>Hola {name}</p>\n                                                <p>El destino ha cambiado</p>\n                                                <p>¡Gracias por usar nuestros servicios!</p>\n                                                <p>Atentamente,</p> \n                                                <p>Sangvish</p>', 'Botón', '<p>Si tiene alguna pregunta, envíenos un correo electrónico a support@gmail.com. Le responderemos y le ayudaremos.</p>', '2021 Missoftwares y derechos reservados', 'El destino de descarga ha cambiado', 'El destino de descarga ha cambiado', 'es', NULL, NULL),
(156, '285d3e51-1c0e-47c2-afc7-63d4e3d5bf63', 'تغيير وجهة الإسقاط للسائق', '<p>مرحبًا {name}\n                                                <p>تم تغيير الوجهة</p>\n                                                <p>شكرًا لاستخدامك خدماتنا!</p>\n                                                <p>مع أطيب التحيات،</p>\n                                                <p>Sangvish</p>', 'زر', '<p>إذا كانت لديك أي استفسارات، يُرجى مراسلتنا عبر البريد الإلكتروني support@gmail.com. سنجيب على استفسارك ونساعدك.</p>', '2021 برامج Misoftware والحقوق محفوظة', 'تم تغيير وجهة الإسقاط', 'تم تغيير وجهة الإسقاط', 'ar', NULL, NULL);

