INSERT INTO `referral_conditions` (`id`, `referral_type`, `label_referral`, `description`, `translation_dataset`, `created_at`, `updated_at`) VALUES
(1, 'instant_referrer_user', 'user', '\n            <ul>\n                <li>\n                    <strong>Share your code</strong>\n                    <ul>\n                        <li>The referrer user will get {referred_user_amount} instantly as a reward after a new user or driver signs up.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Ask friend to download the app</strong>\n                    <ul>\n                        <li>Ask your friends to download the redBus app.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Get rewarded</strong>\n                    <ul>\n                        <li>Earn cash back when your friends register and travel with redBus.</li>\n                    </ul>\n                </li>\n            </ul>', '{\"en\":{\"locale\":\"en\",\"description\":\"\\n            <ul>\\n                <li>\\n                    <strong>Share your code<\\/strong>\\n                    <ul>\\n                        <li>The referrer user will get {referred_user_amount} instantly as a reward after a new user or driver signs up.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Ask friend to download the app<\\/strong>\\n                    <ul>\\n                        <li>Ask your friends to download the redBus app.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Get rewarded<\\/strong>\\n                    <ul>\\n                        <li>Earn cash back when your friends register and travel with redBus.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n            <\\/ul>\"}}', '2026-06-19 02:16:48', '2026-06-19 02:16:48'),
(2, 'instant_referrer_user_and_new_user', 'user', '<ul>\n                <li>\n                    <strong>Share your code</strong>\n                    <ul>\n                        <li>The referrer user receives {referred_user_amount} as a reward for referring a new driver or user, the new user receives {new_user_amount} and new driver gets {new_driver_amount} as a reward immediately after signing up.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Ask friend to download the app</strong>\n                    <ul>\n                        <li>Ask your friends to download the redBus app.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Get rewarded</strong>\n                    <ul>\n                        <li>Earn cash back when your friends register and travel with redBus.</li>\n                    </ul>\n                </li>\n            </ul>', '{\"en\":{\"locale\":\"en\",\"description\":\"<ul>\\n                <li>\\n                    <strong>Share your code<\\/strong>\\n                    <ul>\\n                        <li>The referrer user receives {referred_user_amount} as a reward for referring a new driver or user, the new user receives {new_user_amount} and new driver gets {new_driver_amount} as a reward immediately after signing up.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Ask friend to download the app<\\/strong>\\n                    <ul>\\n                        <li>Ask your friends to download the redBus app.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Get rewarded<\\/strong>\\n                    <ul>\\n                        <li>Earn cash back when your friends register and travel with redBus.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n            <\\/ul>\"}}', '2026-06-19 02:16:48', '2026-06-19 02:16:48'),
(3, 'conditional_for_referrer_user_ride_count', 'user', '<ul>\n                <li>\n                    <strong>Share your code</strong>\n                    <ul>\n                        <li>The referrer user get {referred_user_amount} when your referred user completes {user_ride_count} rides and the driver finishes {driver_ride_count} rides.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Ask friend to download the app</strong>\n                    <ul>\n                        <li>Ask your friends to download the redBus app.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Get rewarded</strong>\n                    <ul>\n                        <li>Earn cash back when your friends register and travel with redBus.</li>\n                    </ul>\n                </li>\n            </ul>', '{\"en\":{\"locale\":\"en\",\"description\":\"<ul>\\n                <li>\\n                    <strong>Share your code<\\/strong>\\n                    <ul>\\n                        <li>The referrer user get {referred_user_amount} when your referred user completes {user_ride_count} rides and the driver finishes {driver_ride_count} rides.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Ask friend to download the app<\\/strong>\\n                    <ul>\\n                        <li>Ask your friends to download the redBus app.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Get rewarded<\\/strong>\\n                    <ul>\\n                        <li>Earn cash back when your friends register and travel with redBus.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n            <\\/ul>\"}}', '2026-06-19 02:16:48', '2026-06-19 02:16:48'),
(4, 'conditional_for_referrer_user_earnings', 'user', '\n            <ul>\n                <li>\n                    <strong>Share your code</strong>\n                    <ul>\n                      <li>The referrer user receives {referred_user_amount} when the user meets the spending requirement of {user_spent_amount} and the driver meets the earning requirement of {driver_earning_amount}.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Ask friend to download the app</strong>\n                    <ul>\n                        <li>Ask your friends to download the redBus app.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Get rewarded</strong>\n                    <ul>\n                        <li>Earn cash back when your friends register and travel with redBus.</li>\n                    </ul>\n                </li>\n            </ul>', '{\"en\":{\"locale\":\"en\",\"description\":\"\\n            <ul>\\n                <li>\\n                    <strong>Share your code<\\/strong>\\n                    <ul>\\n                      <li>The referrer user receives {referred_user_amount} when the user meets the spending requirement of {user_spent_amount} and the driver meets the earning requirement of {driver_earning_amount}.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Ask friend to download the app<\\/strong>\\n                    <ul>\\n                        <li>Ask your friends to download the redBus app.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Get rewarded<\\/strong>\\n                    <ul>\\n                        <li>Earn cash back when your friends register and travel with redBus.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n            <\\/ul>\"}}', '2026-06-19 02:16:48', '2026-06-19 02:16:48'),
(5, 'dual_conditional_for_referrer_user_and_new_user_ride_count', 'user', '<ul>\n                <li>\n                    <strong>Share your code</strong>\n                    <ul>\n                        <li>The referrer user gets {referred_user_amount} when the referred user completes {user_ride_count} rides and the referred driver finishes {driver_ride_count} rides. The new user earns {new_user_amount}, and the new driver earns {new_driver_amount}.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Ask friend to download the app</strong>\n                    <ul>\n                        <li>Ask your friends to download the redBus app.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Get rewarded</strong>\n                    <ul>\n                        <li>Earn cash back when your friends register and travel with redBus.</li>\n                    </ul>\n                </li>\n            </ul>', '{\"en\":{\"locale\":\"en\",\"description\":\"<ul>\\n                <li>\\n                    <strong>Share your code<\\/strong>\\n                    <ul>\\n                        <li>The referrer user gets {referred_user_amount} when the referred user completes {user_ride_count} rides and the referred driver finishes {driver_ride_count} rides. The new user earns {new_user_amount}, and the new driver earns {new_driver_amount}.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Ask friend to download the app<\\/strong>\\n                    <ul>\\n                        <li>Ask your friends to download the redBus app.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Get rewarded<\\/strong>\\n                    <ul>\\n                        <li>Earn cash back when your friends register and travel with redBus.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n            <\\/ul>\"}}', '2026-06-19 02:16:48', '2026-06-19 02:16:48'),
(6, 'dual_conditional_for_referrer_user_and_new_user_earnings', 'user', '<ul>\n                <li>\n                    <strong>Share your code</strong>\n                    <ul>\n                        <li>The referrer user gets {referred_user_amount} when the referred user meets the spending requirement of {user_spent_amount} and the driver meets the earning requirement of {driver_earning_amount}. The new user earns {new_user_amount}, and the new driver earns {new_driver_amount}.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Ask friend to download the app</strong>\n                    <ul>\n                        <li>Ask your friends to download the redBus app.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Get rewarded</strong>\n                    <ul>\n                        <li>Earn cash back when your friends register and travel with redBus.</li>\n                    </ul>\n                </li>\n            </ul>', '{\"en\":{\"locale\":\"en\",\"description\":\"<ul>\\n                <li>\\n                    <strong>Share your code<\\/strong>\\n                    <ul>\\n                        <li>The referrer user gets {referred_user_amount} when the referred user meets the spending requirement of {user_spent_amount} and the driver meets the earning requirement of {driver_earning_amount}. The new user earns {new_user_amount}, and the new driver earns {new_driver_amount}.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Ask friend to download the app<\\/strong>\\n                    <ul>\\n                        <li>Ask your friends to download the redBus app.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Get rewarded<\\/strong>\\n                    <ul>\\n                        <li>Earn cash back when your friends register and travel with redBus.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n            <\\/ul>\"}}', '2026-06-19 02:16:48', '2026-06-19 02:16:48'),
