(13, 'dual_conditional_for_referrer_driver_and_new_driver_or_new_user_earnings', 'driver', '\n            <ul>\n                <li>\n                    <strong>Share your code</strong>\n                    <ul>\n                        <li>The referrer driver gets {referred_driver_amount} when the referred user meets the spending requirement of {user_spent_amount} and the driver meets the earning requirement of {driver_earning_amount}. The new driver earns {new_driver_amount}, and the new user earns {new_user_amount}.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Ask friend to download the app</strong>\n                    <ul>\n                        <li>Ask your friends to download the redBus app.</li>\n                    </ul>\n                </li>\n\n                <li>\n                    <strong>Get rewarded</strong>\n                    <ul>\n                        <li>Earn cash back when your friends register and travel with redBus.</li>\n                    </ul>\n                </li>\n            </ul>\n            ', '{\"en\":{\"locale\":\"en\",\"description\":\"\\n            <ul>\\n                <li>\\n                    <strong>Share your code<\\/strong>\\n                    <ul>\\n                        <li>The referrer driver gets {referred_driver_amount} when the referred user meets the spending requirement of {user_spent_amount} and the driver meets the earning requirement of {driver_earning_amount}. The new driver earns {new_driver_amount}, and the new user earns {new_user_amount}.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Ask friend to download the app<\\/strong>\\n                    <ul>\\n                        <li>Ask your friends to download the redBus app.<\\/li>\\n                    <\\/ul>\\n                <\\/li>\\n\\n                <li>\\n                    <strong>Get rewarded<\\/